<?php/** * Created by PhpStorm. * User: NAGUI * Date: 10/11/2015 * Time: 14:41 */$Bread = "Liste-demandes";/*$Suppid=  filter_input(INPUT_GET,'SuppID',FILTER_VALIDATE_INT);if($Suppid!=""){    update($Suppid,array('public'=>0,'modifier_par'=>$_SESSION['user']['id']),'demande');    header('Location:Liste-demandes');}*/$Limite = filter_input(INPUT_GET, 'd', FILTER_VALIDATE_INT);$idValid = filter_input(INPUT_GET, 'idValid', FILTER_VALIDATE_INT);if ($idValid != "") {    update($idValid, array('validation' => 1, 'modifier_par' => $_SESSION['user']['id']), 'demande');    header('Location:Liste-demandes');}$idBan = filter_input(INPUT_GET, 'idBan', FILTER_VALIDATE_INT);if ($idBan != "") {    update($idBan, array('validation' => -1, 'modifier_par' => $_SESSION['user']['id']), 'demande');    header('Location:Liste-demandes');}$BInv = filter_input(INPUT_POST, 'BInv');if ($BInv) {    $idBinv = filter_input(INPUT_POST, 'id', FILTER_VALIDATE_INT);    update($idBinv, array('budget_investi' => filter_input(INPUT_POST, 'BudgetInvesti')), 'demande');}$where = array('public=' => 1);$link = '';    $de = filter_input(INPUT_GET, 'de',FILTER_SANITIZE_STRING);    $a = filter_input(INPUT_GET, 'a',FILTER_SANITIZE_STRING);    if ($de!="") {        $where['date >= '] = $de;        $link.="&de=$de";    }    if ($a!="") {        $where['date <= '] = $a;        $link.="&a=$a";    }    $usr = filter_input(INPUT_GET, 'user',FILTER_VALIDATE_INT);    if ($usr!="") {        $where['id_user='] = $usr;        $link .= "&user=$usr";    }    $type = filter_input(INPUT_GET, 'typeDm',FILTER_VALIDATE_INT);    if ($type!=""){        $where['type ='] = $type;        $link .= "&typeDm=$type";    }$DemandeID = filter_input(INPUT_GET, 'DemandeID',FILTER_VALIDATE_INT);if ($DemandeID!=""){    $where['id ='] = $DemandeID;    $link .= "&DemandeID=$DemandeID";}    $validation = filter_input(INPUT_GET, 'etat',FILTER_SANITIZE_STRING);    if ($validation!=""){        $where['validation ='] = $validation;        $link .= "&etat=$validation";    }    $Years = filter_input(INPUT_GET, 'Years',FILTER_SANITIZE_STRING);    if ($Years!=""){        $where['year(date) ='] = $Years;        $link .= "&Years=$Years";    }if (!$Limite) $Limite = 0;$ListeDemandes = get('*', 'demande', $where, 'AND', array('id' => 'DESC'), array($Limite, 30));//print_r($ListeDemandes['requete']);//$ListeDemandes = get('*', 'demande',array('public='=>1,));?><section class="content-header">    <h1 class=""> Liste des demandes </h1></section><!-- Main content --><section class="content">    <div class="row">        <div class="col-md-12">            <div class="box box-primary table-responsive">                <div class="pull-right" style="margin: 10px;">                    <form class="form-inline" method="get" action="Liste-demandes">                        <div class="form-group">                            <label>Par Id</label>                            <input type="number" min="1" name="DemandeID" class="form-control" value="<?=$DemandeID?>">                        </div>                        <div class="form-group">                            <select name="etat" id="inputID" class="form-control">                                <option value="" <? if($validation=="") echo "selected='selected'"?>>                                    Par état                                </option>                                <option value="-1" <? if($validation=="-1") echo "selected='selected'"?>>                                    Refuser                                </option>                                <option value="0" <? if($validation=="0") echo "selected='selected'"?>>                                    Non traiter                                </option>                                <option value="1" <? if($validation=="1") echo "selected='selected'"?>>                                    traiter et valider                                </option>                            </select>                        </div>                        <div class="form-group">                            <select name="Years" id="" class="form-control">                                <option value=""> Par années </option>                                <option value="2017"> 2017</option>                                <option value="2016"> 2016</option>                            </select>                        </div>                        <br/>                        <br/>                        <? if ($_SESSION['user']['type'] <= 101): ?>                            <div class="form-group">                                <select class="form-control" name="user">                                    <option value="">Par utilisateur</option>                                    <?                                    $ListeUser = get('*', 'users');                                    foreach ($ListeUser['reponse'] as $user):                                        ?>                                        <option value="<?= $user['id'] ?>" <? if ($user['id'] == $usr) {                                            echo "selected=selected";                                        } ?>><?= $user['Nom'] . ' ' . $user['Prenom'] ?></option>                                    <? endforeach; ?>                                </select>                            </div>                        <? endif ?>                        <div class="form-group">                            <select name="typeDm" class="form-control">                                <option value="">Tous type de demande</option>                                <?                                $ListeTypeDemande = get('*', 'type_demande');                                foreach ($ListeTypeDemande['reponse'] as $demandesT):                                    ?>                                    <option value="<?= $demandesT['id'] ?>" <? if ($demandesT['id'] == $type) {                                        echo "selected=selected";                                    } ?>><?= $demandesT['name'] ?></option>                                <? endforeach; ?>                            </select>                        </div>                        <div class="form-group">                            <label>De </label>                            <input type="date" name="de" class="form-control" value="<?= $de ?>">                        </div>                        <div class="form-group">                            <label>A </label>                            <input type="date" name="a" class="form-control" value="<?= $a ?>"></div>                        <button type="submit" name="Filterdate" value="1" class="btn btn-primary">Filter</button>                        <a href="Liste-demandes" class="btn btn-warning">Annuler</a>                        <? if ($_SESSION['user']['type'] == 1): ?>                            <a href="ToExcel<?= $link ?>" class="btn btn-adn">Extraire</a>                        <? endif; ?>                    </form>                </div>                <div class="clearfix"></div>                <table class="table table-bordered table-condensed table-hover">                    <thead>                    <tr>                        <th>#</th>                        <th>Délégué</th>                        <th>Type</th>                        <th>Date</th>                        <th>B. Demander</th>                        <th>B. Investi</th>                        <th>Action</th>                    </tr>                    </thead>                    <tbody>                    <? foreach ($ListeDemandes['reponse'] as $demande):                            ?>                            <tr class="<?                            if ($demande['VueBySupp'] ==1 && $demande['validation'] == 0) {                                echo 'bg-maroon-gradient';                            }elseif ($demande['validation'] > 0) {                                echo 'bg-green';                            }                            elseif ($demande['validation'] < 0) {                                echo 'bg-yellow-active';                            }                            ?> ">                                <td><?= getinfo(getinfo($demande['type'], 'type_demande', 'departement'), 'departement', 'abr').'/'. $demande['id'] . '/' . date("Y", strtotime($demande['date'])) ?></td>                                <td><?= getinfo($demande['id_user'], 'users', 'Nom') . ' ' . getinfo($demande['id_user'], 'users', 'Prenom') ?></td>                                <td><?= getinfo($demande['type'], 'type_demande', 'name') ?></td>                                <td><?= $StdFunctions->AfficheDateFr($demande['date']) ?></td>                                <td><?=$demande['budget_demander'] ?></td>                                <td><?=$demande['budget_investi'] ?></td>                                <td>                                    <a href="detail?id=<?= $demande['id'] ?>" class="btn btn-pinterest">                                        <span class="glyphicon glyphicon-paperclip"></span>                                    </a>                                </td>                            </tr>                        <?  endforeach; ?>                    </tbody>                </table>            </div>        </div>    </div>    <div class="row">        <div class="col-md-5">            <div class="dataTables_info" id="example2_info" role="status" aria-live="polite">                Affichage de <?= ($Limite > 1) ? $Limite : 1 ?>                à <?= ($Limite + 30 < $ListeDemandes['total']) ? $Limite + 30 : $ListeDemandes['total'] ?>                de <?= $ListeDemandes['total'] ?> Demande            </div>        </div>        <div class="col-md-7">            <div class="dataTables_paginate paging_simple_numbers" id="example2_paginate">                <? pagination($ListeDemandes['total'], 30, WEBRoot . "/dm/Liste-demandes".$link."&d=", ""); ?>            </div>        </div>    </div></section>